"use strict";parserFactory.register("taffygirl13.wordpress.com",()=>new Taffygirl13Parser);class Taffygirl13Parser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(r){let e=[...r.querySelectorAll("div.entry-content figure table")].map(r=>[...r.querySelectorAll("tr")].map(r=>[...r.querySelectorAll("td a")]));if(0==e.length)return super.getChapterUrls(r);let t=[];for(let r of e){let e=[];for(let l of r)t.push(l[0]),2==l.length&&e.push(l[1]);t=t.concat(e)}return t.map(r=>util.hyperLinkToChapter(r))}}